Here's the complete implementation:

```csharp
// In Program.cs

// Configure request size limit (Kestrel)
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 10 * 1024 * 1024; // 10MB
});

// Configure form options
builder.Services.Configure<FormOptions>(options =>
{
    options.MultipartBodyLengthLimit = 10 * 1024 * 1024; // 10MB
});

var app = builder.Build();

// Ensure uploads folder exists
Directory.CreateDirectory(Path.Combine(app.Environment.ContentRootPath, "uploads"));

app.UseAntiforgery();

app.MapPost("/upload", async (IFormFile file, IWebHostEnvironment env) =>
{
    string[] allowedTypes = ["image/jpeg", "image/png"];
    string[] allowedExts = [".jpg", ".jpeg", ".png"];

    if (!allowedTypes.Contains(file.ContentType.ToLowerInvariant()) ||
        !allowedExts.Contains(Path.GetExtension(file.FileName).ToLowerInvariant()))
    {
        return Results.BadRequest("Only JPEG and PNG files are allowed.");
    }

    if (file.Length > 10 * 1024 * 1024)
    {
        return Results.BadRequest("File size must not exceed 10MB.");
    }

    var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
    var filePath = Path.Combine(env.ContentRootPath, "uploads", fileName);

    await using var stream = File.Create(filePath);
    await file.CopyToAsync(stream);

    return Results.Ok(new { fileName });
})
.DisableAntiforgery(); // Remove this line if you want CSRF protection on this endpoint
```

**Key points:**

- **Size limits** are set in both Kestrel and `FormOptions` to enforce the 10MB cap at both layers.
- **`DisableAntiforgery()`** — since you have `UseAntiforgery()` globally, file uploads from API clients (not browsers with forms) will fail without a valid antiforgery token. Remove `.DisableAntiforgery()` if clients will send the token, or keep it for pure API usage.
- **File name** is replaced with a GUID to prevent path traversal and collisions.
- Both content type and extension are validated for defense in depth.
